    static int[] get(String id) {
        return switch (id) {
            case "carrot" -> CARROT;
            case "potato" -> POTATO;
            case "poisonous_potato" -> POISONOUS_POTATO;
            case "beetroot" -> BEETROOT;
            case "wheat" -> WHEAT;
            case "bread" -> BREAD;
            case "pumpkin_pie" -> PUMPKIN_PIE;
            case "melon_slice" -> MELON_SLICE;
            case "golden_carrot" -> GOLDEN_CARROT;
            case "sugar_cane" -> SUGAR_CANE;
            case "apple" -> APPLE;
            case "golden_apple" -> GOLDEN_APPLE;
            case "enchanted_golden_apple" -> ENCHANTED_GOLDEN_APPLE;
            case "glistering_melon_slice" -> GLISTERING_MELON_SLICE;
            case "nether_wart" -> NETHER_WART;
            case "cake" -> CAKE;
            case "glow_berries" -> GLOW_BERRIES;
            case "sweet_berries" -> SWEET_BERRIES;
            case "chorus_fruit" -> CHORUS_FRUIT;
            case "pepper" -> PEPPER;
            case "tomato" -> TOMATO;
            case "corn" -> CORN;
            default -> null;
        };
    }
